  ('aboriginal-6e11b43e-moex-00352', 'aboriginal-6e11b43e', 'aboriginal-6e11b43e-moex-111-3082b5f1', 'sub-aboriginal-6e11b43e-04', NULL, 'single_choice', '受理訴願機關如認為訴願有理由時，其所為之處置，下列何者錯誤？', '["應以決定撤銷原行政處分之全部或一部", "得視事件之情節，逕為變更之決定", "得視事件之情節，發回原行政處分機關另為處分", "於訴願人表示不服之範圍內，得為更不利益之變更或處分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:12+00:00", "source_pdf_sha1": "30267b12713c", "answer_pdf_sha1": "0d471d4816b6", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "504", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "原住民族行政"}'::jsonb, NULL),
